import React, { useState } from 'react';

const handleAddVendor = useCallback((newVendor) => {
  // Send an HTTP request to add the new vendor
  fetch('http://localhost:8081/vendors', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(newVendor),
  })
    .then((response) => {
      if (response.ok) {
        return response.json();
      } else {
        throw new Error('Error adding vendor');
      }
    })
    .then(() => {
      // Refresh the vendors list
      fetch('http://localhost:8081/vendors')
        .then((response) => response.json())
        .then((vendorResponse) => {
          setVendors(vendorResponse);
        })
        .catch((error) => {
          console.log('Error fetching vendors:', error);
        });
    })
    .catch((error) => {
      console.log('Error adding vendor:', error);
    });
}, []);


const AddVendor = ({ handleAddVendor }) => {
  const [newVendor, setNewVendor] = useState({
    name: '',
    field: '',
    mail: '',
    tel: '',
    contactname: ''
    // Add additional fields as needed for the vendor
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewVendor((prevVendor) => ({
      ...prevVendor,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAddVendor(newVendor);
    resetForm();
  };

  const resetForm = () => {
    setNewVendor({
      name: '',
      field: '',
      mail: '',
      tel: '',
      contactname: ''
      // Reset additional fields as needed for the vendor
    });
  };

  return (
    <div className="add-vendor-container">
      <h2 className="add-vendor-heading">Add Vendor</h2>
      <form className="add-vendor-form" onSubmit={handleSubmit}>
        <div className="form-group">
          <label htmlFor="name">Name:</label>
          <input
            type="text"
            id="name"
            name="name"
            value={newVendor.name}
            onChange={handleInputChange}
            required
          />
        </div>
        <div className="form-group">
          <label htmlFor="field">Field:</label>
          <input
            type="field"
            id="field"
            name="field"
            value={newVendor.field}
            onChange={handleInputChange}
            required
          />
        </div>
        <div className="form-group">
          <label htmlFor="name">Mail:</label>
          <input
            type="text"
            id="mail"
            name="mail"
            value={newVendor.mail}
            onChange={handleInputChange}
            required
          />
        </div>
        <div className="form-group">
          <label htmlFor="name">Tel:</label>
          <input
            type="text"
            id="tel"
            name="tel"
            value={newVendor.tel}
            onChange={handleInputChange}
            required
          />
        </div>
        <div className="form-group">
          <label htmlFor="name">Contact Name:</label>
          <input
            type="text"
            id="contactname"
            name="contactname"
            value={newVendor.contactname}
            onChange={handleInputChange}
            required
          />
        </div>
        {/* Add additional form inputs for vendor information */}
        <button type="submit" className="add-vendor-btn">
          Add Vendor
        </button>
      </form>
    </div>
  );
};

export default AddVendor;
